    # If it fails, leave it to Claude

examples.after:
def process_file(path):
    try:
        with open(path) as f:
            return f.read()
    except FileNotFoundError:
        print(f"{path} not found, creating")
        with open(path, "w") as f:
            f.write("")
        return ""

